  window.CONSTITUTION_DATA.articles['article-198'].versions = [{"commit":0,"text":"Each High Court in existence immediately before the commencing day shall continue to have its principal seat at the place where it had such seat before that day."},{"commit":15,"text":"Each High Court in existence immediately before the commencing day shall continue to have its principal seat at the place where it had such seat before that day.\n\n(1A) The High Court for Islamabad Capital Territory shall have its principal seat at Islamabad.\n\n(2) Each High Court shall have a Bench at Bahawalpur, Multan and Rawalpindi.\n\n(3) Each High Court shall have a Bench at Peshawar, Dera Ismail Khan, Abbottabad, Mingora and Bannu, and Quetta, Sibi and Turbat.\n\n(4) Each bench referred to in clause (2) and (3) shall consist of such number of Judges as the Chief Justice of the High Court may, with the approval of the President, appoint.\n\n(5) The Governor in consultation with the Chief Justice of the High Court shall make rules to regulate the practice and procedure of each Bench.\n\n(6) Any decision of a Bench in respect of which no appeal lies to the High Court shall be deemed a decision of the High Court."}];
